it("should throw an error for a damage entry whose item type is not in the policy", () => {
  expect(() =>
    processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword" }],
        },
        {
          op: "claim",
          policy: 0,
          incident: {
            cause: "dragon attack",
            damages: [{ itemType: "amulet", amount: 200 }],
          },
        },
      ],
    })
  ).toThrow();
});
